  \label{lem:presentation_modulesRestrictBasicOpen}
  \lean{AlgebraicGeometry.presentationModulesRestrictBasicOpen}
  \uses{lem:presentation_over_basicOpen, lem:restrict_over_compat,
    lem:presentation_ofIsIso_mathlib, lem:modules_restrict_basicOpen}
  % NOTE: to-build (Route B, step B4).
  Let \(\mathcal{F}\) be an \(\mathcal{O}_{\operatorname{Spec} R}\)-module, let \(U\) be an open
  carrying a presentation of \(\mathcal{F}.\operatorname{over} U\), and let \(g \in R\) with
  \(D(g) \subseteq U\). Then the affine restriction \(\mathcal{F}_{(g)} =
  \operatorname{modulesRestrictBasicOpen} g\, \mathcal{F}\), as an
  \((\operatorname{Spec} R_g).\mathrm{Modules}\)-object, admits a global presentation.
\end{lemma}
\begin{proof}
  \uses{lem:presentation_over_basicOpen, lem:restrict_over_compat,
    lem:presentation_ofIsIso_mathlib, lem:modules_restrict_basicOpen}
    \leanok
  By Lemma~\ref{lem:presentation_over_basicOpen}, \(\mathcal{F}.\operatorname{over} D(g)\) admits a
  presentation. Transport it across the bridge isomorphism
  \(\mathcal{F}.\operatorname{over} D(g) \cong \mathcal{F}_{(g)}\)
  (Lemma~\ref{lem:restrict_over_compat}) together with the comparison isomorphism of
  Lemma~\ref{lem:modules_restrict_basicOpen}, using Lemma~\ref{lem:presentation_ofIsIso_mathlib}, to
  obtain a presentation of \(\mathcal{F}_{(g)}\).
\end{proof}

